class Solution {
    double r, xc, yc;
public:
    Solution(double radius, double x_center, double y_center):r(radius),xc(x_center),yc(y_center){}
    vector<double> randPoint() {
        while(true){
            double x=((double)rand()/RAND_MAX*2-1)*r+xc;
            double y=((double)rand()/RAND_MAX*2-1)*r+yc;
            if((x-xc)*(x-xc)+(y-yc)*(y-yc)<=r*r) return {x,y};
        }
    }
};
